(()=>{
  'use strict';
  const $=id=>document.getElementById(id);
  const now=()=>new Date().toISOString();
  const CANON={productionUrl:'https://montrealai.github.io/goalos-agijobmanager-ascension/',manager:'0xB3AAeb69b630f0299791679c063d68d6687481d1',agialpha:'0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA',chainId:1,externalActions:0,walletCalls:0,networkRequests:0,userDataWanted:false};
  const objectMarkers='ChronicleEntry CapabilityPackage';
  const law=['bounded work','observable trace','evidence package','validator judgment','risk state','Chronicle memory','settlement decision','reusable capability'];
  const gates=['Mission Contract','Agent Allocation','Tool Scope','Work Trace','Proof Bundle','Validator Mesh','Risk Ledger','Settlement Check','Chronicle Memory','Human Review'];
  const agents=[
    {id:'mission-architect',name:'Mission Architect',role:'objective → GoalOSCommit',score:91},
    {id:'planner',name:'Planner',role:'decomposition + budget',score:87},
    {id:'worker',name:'Worker',role:'bounded execution',score:84},
    {id:'proofsmith',name:'Proofsmith',role:'trace → ProofPacket',score:93},
    {id:'verifier',name:'Verifier',role:'evidence gate',score:95},
    {id:'risk-sentinel',name:'Risk Sentinel',role:'risk + rollback',score:90},
    {id:'settlement',name:'Settlement Steward',role:'accept / reject / dispute',score:88},
    {id:'chronicle',name:'Chronicle Keeper',role:'memory + reuse',score:92},
    {id:'human-reviewer',name:'Human Reviewer',role:'final authority',score:100}
  ];
  const missions={
    market:{title:'Proof-settled market brief',risk:'medium',objective:'Produce an evidence-governed market brief with assumptions, risks, validator notes, and reusable capability package.'},
    software:{title:'Validator-ready software task',risk:'medium',objective:'Simulate a proof-native software repair mission: spec, patch artifact, tests, risk ledger, verifier report, and rollback path.'},
    dispute:{title:'Dispute-resolution rehearsal',risk:'high',objective:'Walk a contested AGIJobManager lifecycle event through evidence, validator disagreement, challenge window, and human review.'},
    economy:{title:'Sovereign Machine Economy walkthrough',risk:'high',objective:'Coordinate Meta-Agentic cognition, Alpha Node runtime, AGI Jobs work OS, AGIJobManager settlement, Chronicle, and reusable capability.'},
    policy:{title:'Data-Zero boundary check',risk:'high',objective:'Verify that a browser-local mission can produce a public-safe proof pack without collecting personal, confidential, regulated, wallet, or customer data.'}
  };
  const state={step:0,mission:'market',running:false,timer:null,trace:[],metrics:{verified:0,entropy:48,proofDebt:100,risk:36,reuse:0,readiness:0}};
  const demoNote='Browser-local simulation only. No account, no cookies, no analytics, no storage, no wallet, no network request, no Mainnet broadcast.';
  function initParticles(){const c=$('institutionParticles');if(!c||c.dataset.ready)return;c.dataset.ready='1';const ctx=c.getContext('2d');let w=0,h=0;const dots=Array.from({length:96},(_,i)=>({x:Math.random(),y:Math.random(),v:.18+Math.random()*.72,r:1+Math.random()*2.4,a:.2+Math.random()*.6,h:i%4}));function size(){w=c.width=innerWidth*devicePixelRatio;h=c.height=innerHeight*devicePixelRatio}addEventListener('resize',size,{passive:true});size();function frame(){ctx.clearRect(0,0,w,h);for(const d of dots){d.y-=d.v/innerHeight;if(d.y<-.04){d.y=1.04;d.x=Math.random();d.v=.18+Math.random()*.72}const x=d.x*w,y=d.y*h;ctx.beginPath();ctx.fillStyle=d.h===0?'rgba(152,255,217,'+d.a+')':d.h===1?'rgba(116,198,255,'+d.a+')':d.h===2?'rgba(255,232,142,'+d.a+')':'rgba(170,145,255,'+d.a+')';ctx.arc(x,y,d.r*devicePixelRatio,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.strokeStyle='rgba(94,249,229,.10)';ctx.moveTo(x,y+12*devicePixelRatio);ctx.lineTo(x,y+42*devicePixelRatio);ctx.stroke()}requestAnimationFrame(frame)}frame()}
  function setMission(id){state.mission=id;document.querySelectorAll('[data-mission]').forEach(b=>b.classList.toggle('active',b.dataset.mission===id));const m=missions[id];const obj=$('missionObjective');if(obj&&!obj.dataset.edited)obj.value=m.objective;const label=$('missionTitle');if(label)label.textContent=m.title;const risk=$('riskClass');if(risk)risk.value=m.risk;renderPreview()}
  function reset(){clearInterval(state.timer);state.step=0;state.running=false;state.trace=[];state.metrics={verified:0,entropy:48,proofDebt:100,risk:36,reuse:0,readiness:0};render()}
  function run(){if(state.running)return;state.running=true;state.trace=[`0. ${now()} · Mission contracted · ${missions[state.mission].title}`,`1. Boundary check · ${demoNote}`];render();state.timer=setInterval(()=>{if(state.step>=gates.length){clearInterval(state.timer);state.running=false;state.trace.push(`${state.trace.length}. HUMAN_REVIEW_REQUIRED · proof package ready; no authority self-granted.`);render();return}state.step++;advanceMetrics();state.trace.push(`${state.trace.length}. ${gates[state.step-1]} · passed local simulated gate · external actions=${CANON.externalActions}`);render()},700)}
  function advanceMetrics(){state.metrics.verified=Math.min(100,Math.round(state.step*9.7));state.metrics.entropy=Math.max(35,Math.round(54-state.step*1.7));state.metrics.proofDebt=Math.max(0,Math.round(100-state.step*9.6));state.metrics.risk=Math.max(6,Math.round(36-state.step*2.4));state.metrics.reuse=Math.min(94,Math.round(state.step*8.8));state.metrics.readiness=Math.min(100,Math.round(state.step*10))}
  function render(){renderGates();renderAgents();renderMetrics();renderTrace();renderPreview();document.querySelectorAll('[data-node]').forEach(n=>n.classList.toggle('active',Number(n.dataset.node)===Math.min(state.step,6)))}
  function renderGates(){const el=$('institutionGates');if(!el)return;el.innerHTML=gates.map((g,i)=>`<div class="gate ${i<state.step?'done':i===state.step&&state.running?'running':''}"><small>${String(i+1).padStart(2,'0')}</small><b>${g}</b></div>`).join('')}
  function renderAgents(){const el=$('agentGrid');if(!el)return;el.innerHTML=agents.map((a,i)=>`<div class="agent-tile ${i<=Math.min(state.step,agents.length-1)?'active':''}"><div class="tag">${a.id}</div><b>${a.name}</b><p>${a.role}</p><small>score ${a.score}</small></div>`).join('')}
  function renderMetrics(){const m=state.metrics;const assign=(id,v)=>{const el=$(id);if(el)el.textContent=v};assign('metricVerified',m.verified);assign('metricEntropy',m.entropy);assign('metricProofDebt',m.proofDebt);assign('metricRisk',m.risk);assign('metricReuse',m.reuse);assign('metricReadiness',m.readiness);const r=$('readinessRing');if(r)r.style.setProperty('--readiness',m.readiness+'%')}
  function renderTrace(){const el=$('traceLog');if(el)el.textContent=state.trace.join('\n')||'Awaiting mission. The proof-governed institution has not started.'}
  function goalOSCommit(){return{type:'GoalOSCommit',objective:(($('missionObjective')||{}).value||missions[state.mission].objective).slice(0,900),successCriteria:['bounded work','observable trace','Evidence Docket export','human review boundary'],failureCriteria:['missing evidence','unbounded action','private data entered','wallet or network action on demo surface'],constraints:['browser-local','data-zero','public-safe','no wallet','no network','no external action'],riskClass:(($('riskClass')||{}).value||missions[state.mission].risk),rollbackObligations:['reset local simulation','discard generated JSON if not needed'],claimBoundary:'simulation only; no factual certification; no production authority; no Mainnet transaction'} }
  function docket(){const commit=goalOSCommit();return{schema:'goalos.multi-agent-institution.docket.v17',generatedAt:now(),canonical:CANON,mission:missions[state.mission].title,doctrine:'Large multi-agent systems coordinate to maximum effect when they become proof-governed sovereign institutions.',coordinationLaw:'Maximum coordination = maximum verified useful work per unit of risk, cost, latency, and proof debt.',workEquation:'AI Work = Output × Proof × Validation × Settlement × Reuse',goalOSCommit:commit,runCommitment:{type:'RunCommitment',agentSet:agents.map(a=>a.id),toolPermissions:['none in public demo'],budgetLimit:'local-simulation-only',runtimeEnvironment:'browser-local static page'},proofPacket:{type:'ProofPacket',traceRoot:'local-simulated-trace-'+state.trace.length,outputHash:'browser-local-demo-output',policyDecisionRoot:'data-zero-default-deny',cost:{walletCalls:0,networkRequests:0,externalActions:0},latency:'simulated',errors:[],evidenceURI:'downloaded-json'},evalAttestation:{type:'EvalAttestation',verdict:state.step>=10?'PASS_SIMULATED':'IN_PROGRESS',validator:'local proof-gate simulator',humanReviewRequired:true},selectionCertificate:{type:'SelectionCertificate',decision:state.step>=10?'READY_FOR_HUMAN_REVIEW':'NOT_READY',scope:'demo only',rollbackTarget:'reset simulation',challengeWindow:'not applicable to local demo'},chronicleEntry:{acceptedMemory:state.step>=10?'public-safe proof pattern only':'none',reuseCandidate:'capability package template',terminalState:'HUMAN_REVIEW_REQUIRED'},metrics:state.metrics,agents,proofGates:gates.map((g,i)=>({gate:g,status:i<state.step?'passed':i===state.step&&state.running?'running':'queued'})),trace:state.trace,legalBoundary:{noUserDataWanted:true,noAnalytics:true,noCookies:true,noForms:true,noStorage:true,noInvestmentAdvice:true,noTokenAvailabilityFromSite:true,userOperatorResponsibility:true},note:demoNote}}
  function renderPreview(){const el=$('docketPreview');if(el)el.textContent=JSON.stringify(docket(),null,2)}
  function downloadDocket(){const data=JSON.stringify(docket(),null,2);const blob=new Blob([data],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='goalos-multi-agent-institution-docket-v17.json';document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(url),900)}
  async function copySummary(){const text='Large multi-agent systems coordinate to maximum effect when they become proof-governed sovereign institutions. GoalOS turns objectives into bounded work, proof, validation, settlement, Chronicle memory, and reusable capability. Demo is browser-local and public-safe.';try{await navigator.clipboard.writeText(text);const c=$('copyStatus');if(c)c.textContent='Copied public-safe summary.'}catch(e){const c=$('copyStatus');if(c)c.textContent='Copy unavailable in this browser.'}}
  function bind(){initParticles();document.querySelectorAll('[data-mission]').forEach(b=>b.addEventListener('click',()=>setMission(b.dataset.mission)));const obj=$('missionObjective');if(obj)obj.addEventListener('input',()=>{obj.dataset.edited='1';renderPreview()});const risk=$('riskClass');if(risk)risk.addEventListener('change',renderPreview);const runBtn=$('runInstitution');if(runBtn)runBtn.addEventListener('click',run);const resetBtn=$('resetInstitution');if(resetBtn)resetBtn.addEventListener('click',reset);const exportBtn=$('exportInstitutionDocket');if(exportBtn)exportBtn.addEventListener('click',downloadDocket);const copyBtn=$('copyInstitutionSummary');if(copyBtn)copyBtn.addEventListener('click',copySummary);setMission(state.mission);reset()}
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',bind);else bind();
})();
